    {%- set maxValue = maxValue-%}
    {%- set filterCondition = filterCondition-%}
    select * from (
        select count(*) numberOfRecordActual  from {{this}}  
            {%- if filterCondition %}
                Where {{filterCondition}}
            {%- endif -%}
            {%- if group_by %}
                GROUP BY "{{ group_by | join('", "') }}"
            {%- endif -%}            
