    {%- set is_numeric = sum_total | float(0) != 0 or sum_total == "0" -%}
    {%- if is_numeric -%}
        {% set target_expression = sum_total -%}
    {%- else %}
        {% set target_expression = 'SUM("' ~ sum_total ~ '")' -%}
    {%- endif %}

    {%- set group_by_clause = "" -%}
