    {%- endif %}

    {# --- Tests --- #}
    {%- if configTests is defined and configTests.parameters is defined %}
        {%- for test in configTests.parameters %}
            {%- set testParts = test.split(':', 1) %}
            {%- set continueOnFailure = testParts[0] | trim | lower == 'continueonfailure' %}
            {{ test_stage(node.name + testName + loop.index|string, continueOnFailure) }}
            {{ testParts[-1] | trim }}
