    {%- endif %}

    {%- if runOrder == 'After' %}
        {%- for column in columns %}
            {%- if column.tests is mapping and column.tests.parameters is defined %}
                {%- for test in column.tests.parameters %}
                    {%- if test | trim | lower == "null" %}
                        {%- set templateString = "SELECT 1 FROM " +  ref(node.location.name, node.name)  + " WHERE " + column.name + " IS NULL " %}                      
                        {{ test_stage("Column Test: " + column.name + " - " + test | lower) }}
                        {{ templateString }}
                    {%- endif %}
                    {%- if test | trim | lower == "unique" %}
                        {%- set templateString = "SELECT 1 FROM " + ref(node.location.name, node.name) + " GROUP BY " + column.name +  " HAVING COUNT(*) > 1" %}                      
                        {{ test_stage("Column Test: " + column.name + " - " + test | lower) }}
                        {{ templateString }}
                    {%- endif %}
                {%- endfor %}
            {%- endif %}
        {%- endfor %}
    {%- endif %}

{%- endmacro %}

{# ===================================================================================================== 
Description:
Performs pre-validation checks on column metadata before executing a MERGE operation.
Ensures required column annotations are present and consistent based on the merge type
(standard, last-modified based, or SCD Type 2).

This macro is intended to fail fast with clear warnings if required configurations
are missing or incorrectly defined.

Inputs:
- columns (implicit):
