    {%- endif %}

    {%- set currentFlagCol = get_value_by_column_attribute("isSystemCurrentFlag") %}
    {%- set versionCol = get_value_by_column_attribute("isSystemVersion") %}
    {%- set createDate = get_value_by_column_attribute("isSystemCreateDate") %}
    {%- set updateDate = get_value_by_column_attribute("isSystemUpdateDate") %}

    {%- if type2Dimension %}

        {%- set endDate = get_value_by_column_attribute("isSystemEndDate") %}

        {%- if lastModifiedComparison %}

            {#== SCD type 2 - LM ==#}
            {%- if 'ERR:' in createDate or 'ERR:' in endDate or 'ERR:' in currentFlagCol or 'ERR:' in versionCol %}
                {{ test_stage('Warning! Missing audit/version/status/metadata columns', false) }}
                /*
                It is recommended to also include columns with annotations @isSurrogateKey, @isSystemCurrentFlag, @isSystemVersion, @isSystemCreateDate and @isSystemEndDate for improved clarity and auditability.
                Please specify it using @isSurrogateKey, @isSystemCurrentFlag, @isSystemVersion, @isSystemCreateDate, @isSystemEndDate at the column level in SQL.

                Example:

                "{{ node.name }}_KEY"::NUMBER AS "{{ node.name }}_KEY" @isSurrogateKey,
                "SYSTEM_CURRENT_FLAG"::VARCHAR AS "SYSTEM_CURRENT_FLAG" @isSystemCurrentFlag,
                "SYSTEM_VERSION"::NUMBER AS "SYSTEM_VERSION" @isSystemVersion,
                CAST(CURRENT_TIMESTAMP AS TIMESTAMP) AS "SYSTEM_CREATE_DATE" @isSystemCreateDate,
                CAST('2999-12-31 00:00:00' AS TIMESTAMP) AS "SYSTEM_END_DATE" @isSystemEndDate

                */
                SELECT CAST('FAIL' AS STRING)
            {%- endif %}
        {%- else %}
            {#== SCD type 2 - CT ==#}
            {%- if 'ERR:' in createDate or 'ERR:' in updateDate or 'ERR:' in endDate or 'ERR:' in currentFlagCol or 'ERR:' in versionCol %}
                {{ test_stage('Warning! Missing audit/version/status/metadata columns', false) }}
                /*
                It is recommended to also include columns with annotations @isSurrogateKey, @isSystemCurrentFlag, @isSystemVersion, @isSystemCreateDate, @isSystemUpdateDate and @isSystemEndDate for improved clarity and auditability.
                Please specify it using @isSurrogateKey, @isSystemCurrentFlag, @isSystemVersion, @isSystemCreateDate, @isSystemUpdateDate and @isSystemEndDate at the column level in SQL.

                Example:

                "{{ node.name }}_KEY"::NUMBER AS "{{ node.name }}_KEY" @isSurrogateKey,
                "SYSTEM_CURRENT_FLAG"::VARCHAR AS "SYSTEM_CURRENT_FLAG" @isSystemCurrentFlag,
                "SYSTEM_VERSION"::NUMBER AS "SYSTEM_VERSION" @isSystemVersion,
                CAST(CURRENT_TIMESTAMP AS TIMESTAMP) AS "SYSTEM_CREATE_DATE" @isSystemCreateDate,
                CAST(CURRENT_TIMESTAMP AS TIMESTAMP) AS "SYSTEM_UPDATE_DATE" @isSystemUpdateDate,
                CAST('2999-12-31 00:00:00' AS TIMESTAMP) AS "SYSTEM_END_DATE" @isSystemEndDate

                */
                SELECT CAST('FAIL' AS STRING)
            {%- endif %}
        {%- endif %}
    {%- else %}
        {#== SCD type 1 - Without Delete Strategy ==#}
        {%- if 'ERR:' in createDate or 'ERR:' in updateDate %}
            {{ test_stage('Warning! Missing audit/metadata columns', true) }}
            /*
            It is recommended to also include columns with annotations @isSystemCreateDate, @isSystemUpdateDate for improved clarity and auditability.
            Please specify it using @isSystemCreateDate, @isSystemUpdateDate at the column level in SQL.

            Example:

            CAST(CURRENT_TIMESTAMP AS TIMESTAMP) AS "SYSTEM_CREATE_DATE" @isSystemCreateDate,
            CAST(CURRENT_TIMESTAMP AS TIMESTAMP) AS "SYSTEM_UPDATE_DATE" @isSystemUpdateDate

            */
            SELECT CAST('FAIL' AS STRING)
        {%- endif %}
    {%- endif %}
{%- endmacro %}

{# ====================================================================================================
Description:
Generates a datatype-aware equality comparison between a source and target expression.
Designed for use in WHERE / JOIN conditions where different Snowflake datatypes
require different comparison logic.

Inputs:
- src_expr (string):
    Source column or expression (e.g., SRC."COL1")

- tgt_expr (string):
    Target column or expression (e.g., "DIM"."COL1")

- data_type (string):
    Datatype of the column (e.g., VARCHAR, NUMBER, GEOGRAPHY, GEOMETRY)

Output:
- Returns a SQL boolean condition that evaluates to TRUE when source and target values are equal
====================================================================================================#}
{%- macro safe_equals(src_expr, tgt_expr, data_type) %}

    {%- set dt = data_type | upper %}

    {%- if 'GEOGRAPHY' in dt %}
        (
            ST_DISTANCE(
                COALESCE({{ src_expr }}, TO_GEOGRAPHY('POINT(0 0)')),
                COALESCE({{ tgt_expr }}, TO_GEOGRAPHY('POINT(0 0)'))
            ) = 0
        )
    {%- elif 'GEOMETRY' in dt %}
        (
            ST_DISTANCE(
                COALESCE({{ src_expr }}, TO_GEOMETRY('POINT(0 0)')),
                COALESCE({{ tgt_expr }}, TO_GEOMETRY('POINT(0 0)'))
            ) = 0
        )
    {%- else %}
        {{ src_expr }} = {{ tgt_expr }}
    {%- endif %}
{%- endmacro %}

{#====================================================================================================
Description:
Generates a datatype-aware comparison to detect differences between a source and
target expression. Typically used in MERGE statements or change tracking logic
to identify when a column value has changed.

Inputs:
- src_expr (string):
    Source column or expression (e.g., SRC."COL1")

- tgt_expr (string):
    Target column or expression (e.g., "DIM"."COL1")

- data_type (string):
    Datatype of the column (e.g., VARCHAR, NUMBER, GEOGRAPHY, GEOMETRY)

Output:
- Returns a SQL boolean condition that evaluates to TRUE when source and target values are different
====================================================================================================#}
{%- macro safe_compare(src_expr, tgt_expr, data_type) %}

    {%- set dt = data_type | upper %}

    {%- if 'GEOGRAPHY' in dt %}
        (
            ST_DISTANCE(
                COALESCE({{ src_expr }}, TO_GEOGRAPHY('POINT(0 0)')),
                COALESCE({{ tgt_expr }}, TO_GEOGRAPHY('POINT(0 0)'))
            ) > 0
        )
    {%- elif 'GEOMETRY' in dt %}
        (
            ST_DISTANCE(
                COALESCE({{ src_expr }}, TO_GEOMETRY('POINT(0 0)')),
                COALESCE({{ tgt_expr }}, TO_GEOMETRY('POINT(0 0)'))
            ) > 0
        )
    {%- else %}
        {{ src_expr }} IS DISTINCT FROM {{ tgt_expr }}
    {%- endif %}

{%- endmacro %}

{#===================================================================================================
Description:
Generates a deterministic hash value by combining and hashing all column values associated with the given `hash_name` using the `@hashValue` annotation.

Input: `hash_name` (string) - The hash group identifier used in `@hashValue("<hash_name>")` to group columns for hashing.

Output: - Returns a SQL expression of type `STRING`:
        - A SHA1 hash of concatenated column values  
        - Returns `NULL` if no columns are mapped to the given hash group
====================================================================================================#}
{%- macro get_hash(hash_name, algo='SHA1') -%}

    {%- set cols = namespace(name=[]) -%}
    {%- set algo_upper = algo | upper -%}

    {# collect columns #}
    {%- for col in sources[0].columns -%}
        {%- if col.hashValue is defined 
              and col.hashValue.parameters is defined 
              and hash_name in col.hashValue.parameters -%}
            {%- set cols.name = cols.name + [col.transform] -%}
        {%- endif -%}
    {%- endfor -%}

    {%- if cols.name | length == 0 -%}
        NULL
    {%- else -%}

        {# define algo wrappers #}
        {%- set algo_start = algo_upper + '(' %}
        {%- set algo_end = ')' %}

        {%- if algo_upper == 'SHA256' %}
            {%- set algo_start = 'SHA2(' %}
            {%- set algo_end = ', 256)' %}
        {%- endif %}

        CAST(
            {{ algo_start }}
                {%- for c in cols.name -%}
                    {%- if not loop.first %} || {%- endif -%}
                    NVL(CAST({{ c }} AS VARCHAR), 'null')
                {%- endfor -%}
            {{ algo_end }}
        AS STRING)

    {%- endif -%}

{%- endmacro -%}

{#====================================================================================================
Description:
    Returns a zero-key value for a given column based on:
    1. Column-level zeroKey (highest priority)
    2. Config-level zeroKey (matched using column dataType)
    3. If no match is found → returns NULL

    The macro ONLY resolves and formats the zero-key value.
    It does not handle system columns or any business logic.

Inputs:
    col (object)

Output:
    Returns a SQL-compatible literal based on resolved zeroKey:
        - NUMBER    → 0
        - BOOLEAN   → TRUE / FALSE
        - STRING    → 'DEFAULT'
        - TIME      → TO_TIMESTAMP('1999-12-31')
        - No match  → NULL
====================================================================================================#}
{%- macro resolve_zero_key(col) %}

    {%- set ns = namespace(zk_type=none, zk_value=none) %}

    {# -------------------------------
       STEP 1: Column-level zeroKey
    -------------------------------- #}
    {%- if col.zeroKey is defined 
          and col.zeroKey.parameters is defined 
          and col.zeroKey.parameters | trim | length > 0 %}

        {%- set ns.zk_value = col.zeroKey.parameters[0] %}

    {# -------------------------------
       STEP 2: Config-level zeroKey (match datatype)
    -------------------------------- #}
    {%- elif config.zeroKey is defined 
          and config.zeroKey.parameters is defined 
          and config.zeroKey.parameters | trim | length > 0 %}

        {%- for zk in config.zeroKey.parameters %}
            {%- set parts = zk.split(':', 1) %}
            {%- set type = parts[0] | trim | lower %}
            {%- set val = parts[-1] | trim %}

            {%- if ((type == 'string' and col.dataType[:3] | upper in ('VAR', 'CHA', 'STR')) or
                    (type == 'boolean' and col.dataType | upper == 'BOOLEAN') or
                    (type == 'datetime' and col.dataType[:4] | upper in ('DATE', 'TIME', 'TIMESTAMP'))
            ) %}
                {%- set ns.zk_type = type %}
                {%- set ns.zk_value = val %}
            {%- endif %}
        {%- endfor %}

    {%- else %}
        {%- set ns.zk_type = none %}
        {%- set ns.zk_value = none %}
    {%- endif %}

    {# -------------------------------
       STEP 3: Return formatted value
    -------------------------------- #}
    {%- if col.dataType[:3] | upper in ('NUM',' INT', 'DEC', 'FLO') %}
        0
    {%- elif ns.zk_value is not none %}
        {%- if ns.zk_type == 'boolean' %}
            {{ ns.zk_value | upper }}

        {%- elif ns.zk_type == 'datetime' %}
            TO_TIMESTAMP('{{ ns.zk_value }}')

        {%- elif ns.zk_type == 'string' %}
            '{{ ns.zk_value }}'

        {%- else %}
            '{{ ns.zk_value }}'
        {%- endif %}

    {%- else %}
        NULL
    {%- endif %}

{%- endmacro %}

