    AS    
    {{ sources[0].cteString }}
    SELECT {%- if config.selectDistinct %} DISTINCT {%- endif %}
    {%- for col in sources[0].columns %}
        {{ get_source_transform(col) }} AS "{{ col.name }}"
        {%- if not loop.last -%}, {%- endif %}
    {%- endfor %}

    {{ sources[0].join }}

{%- endif %}

run.templateString:
{#
    Copyright (c) 2026 Coalesce. All rights reserved.
This script and its associated documentation are confidential and proprietary to Coalesce.
Unauthorized reproduction, distribution, or disclosure of this material is strictly prohibited.
Coalesce permits you to copy and modify this script for the purposes of using with Coalesce but
does not permit copying or modification for any other purpose.  
#}
{# == Node Type Name           : SQL Merge  == #}
{# == Node Type Description    : This node loads data into work table using options distinct, groupby all, order by, multi-source  == #}

{# == To run data quality tests before data insertion == #}
{{ run_tests('Before') }}

{%- if node.materializationType | lower == 'table' %}

    {{ validate_merge_columns() }}

    {# == Check if last modified comparison is enabled  #}
    {%- set hasBusinessKey = columns | selectattr("isBusinessKey") | list | length > 0 | default(false) %}

    {%- if hasBusinessKey %}
        {%- set lastModifiedComparison = columns | selectattr("isLastModifiedColumn") | list | length > 0 | default(false) %}
        {%- if lastModifiedComparison %}
            {%- if columns | selectattr("isLastModifiedColumn") | list | length == 1 %}
                {%- set lastModifiedCol = columns | selectattr('isLastModifiedColumn') | list | first %}
                {%- set lastModifiedColName = lastModifiedCol.name %}
                {%- set isTimeStamp = lastModifiedCol 
                    and lastModifiedCol.dataType is defined 
                    and (lastModifiedCol.dataType | upper).startswith('TIME') | default(false) %}
                {%- set treatNullAsCurrentTimestamp = isTimeStamp and config.treatNullAsCurrentTimestamp | default(false) %}
                {%- set type2Dimension = config.type2Dimension | default(false) %}
            {%- endif %}
        {%- else %}
            {%- set type2Dimension = columns | selectattr("isChangeTracking") | list | length > 0 | default(false) %}
        {%- endif %}
    {%- endif %}

    {#== Pre-SQL ==#}
    {%- if config.preSQL is defined and config.preSQL.parameters is defined %}
        {%- for sql in config.preSQL.parameters %}
            {{ stage('Pre-SQL ' + loop.index|string) }}
            {{ sql }}
        {%- endfor %}
    {%- endif %}

	{# == Truncate data before data insertion  == #}
    {%- if config.truncateBefore %}
        {{ stage('Truncate ' + node.materializationType) }}
        TRUNCATE IF EXISTS {{ ref_no_link(node.location.name, node.name) }}
    {%- endif %}

    {%- set source = sources[0] %}
    {%- set joinclause = source.join %}

    {%- set hasZeroKey = columns 
                        | selectattr('isSurrogateKey') 
                        | selectattr('zeroKey', 'defined') 
                        | selectattr('zeroKey.parameters', 'defined') 
                        | list 
                        | length > 0 
                        and (config.zeroKey is defined and config.zeroKey.parameters is defined)
    %}

    {%- if hasZeroKey %}
        {{ stage('Load ' + node.materializationType + ' Using Merge - Zero Key Record') }}
            MERGE INTO {{ ref_no_link(node.location.name, node.name) }} USING
            (
                SELECT 
                {%- for col in source.columns %}

                    {%- if col.isSystemCurrentFlag %}
                        'Y'
                    {%- elif col.isSystemStartDate or col.isSystemEndDate or col.isSystemUpdateDate or col.isSystemCreateDate %}
                        {{ get_source_transform(col) }}
                    {%- elif col.isSystemVersion %}
                        1
                    {%- else %}
                        {{ resolve_zero_key(col) }}
                    {%- endif %}
                    AS "{{ col.name }}"
                    {%- if not loop.last %}, {%- endif %}
                {%- endfor %}
                FROM DUAL
            ) AS SOURCE_ZERO

            ON
            {%- for col in columns if col.isSurrogateKey %}
                "{{ node.name }}"."{{ col.name }}" = {{ col.zeroKey.parameters[0] }}
            {%- endfor %}

            WHEN MATCHED THEN UPDATE
            SET
            {%- for col in columns if (not col.isSurrogateKey) %}
                "{{ node.name }}"."{{ col.name }}" = "SOURCE_ZERO"."{{ col.name }}"
                {%- if not loop.last %}, {%- endif %}			
            {%- endfor %}

            WHEN NOT MATCHED THEN
            INSERT
            (
                {%- for col in columns %}
                    "{{ col.name }}"
                    {%- if not loop.last %}, {%- endif %}			
                {%- endfor %}
            )
            VALUES
            (
                {%- for col in columns %}
                    "SOURCE_ZERO"."{{ col.name }}"			
                    {%- if not loop.last %}, {%- endif %}			
                {%- endfor %}
            )
    {%- endif %}

    {%- if lastModifiedComparison %}
        {#== Last Modified SCD ==#}
        {%- if type2Dimension %}
            {{ stage('Load ' + node.materializationType + ' Using Merge - Last Modified Comparison - SCD2') }}
        {%- else %}
            {{ stage('Load ' + node.materializationType + ' Using Merge - Last Modified Comparison - SCD1') }}
        {%- endif %}
    {%- else %}
        {#== Change Tracking SCD ==#}
        {%- if type2Dimension %}
            {{ stage('Load ' + node.materializationType + ' Using Merge - Change Tracking - SCD2') }}
        {%- else %}
            {{ stage('Load ' + node.materializationType + ' Using Merge - Change Tracking - SCD1') }}
        {%- endif %}
    {%- endif %}

    MERGE INTO {{ ref_no_link(node.location.name, node.name) }} "TGT"
    USING (

        {{ source.cteString }}

        {%- if type2Dimension %}

            {#== SCD Type 2 ==#}
            /* New Rows That Don't Exist */
            (
                SELECT {%- if config.selectDistinct %} DISTINCT {%- endif %}
                {%- for col in source.columns if not col.isSurrogateKey %}
                    {%- if col.isSystemVersion %}
                    1
                    {%- elif col.isSystemCurrentFlag %}
                    'Y'
                    {%- else %}
                    {{ get_source_transform(col) }}
                    {%- endif %}
                    AS "{{ col.name }}",
                {%- endfor %}
                'INSERT_NEW_ROWS' AS "DML_OPERATION"
                {{ get_clause(joinclause, 'from') }}

                LEFT JOIN {{ ref_no_link(node.location.name, node.name) }} "DIM" ON
                {%- for col in source.columns if col.isBusinessKey %}
                    {%- if not loop.first %}
                    AND
                    {%- endif %}
                    {{ get_source_transform(col) }} = "DIM"."{{ col.name }}"
                {%- endfor %}
                WHERE
                {%- for col in source.columns if col.isBusinessKey %}
                    {%- if not loop.first %}
                    AND
                    {%- endif %}
                    "DIM"."{{ col.name }}" IS NULL
                {%- endfor %}
                {{ get_clause(joinclause) }}
                {%- if config.groupByAll %} GROUP BY ALL {%- endif %}
            )

            UNION ALL

            {%- if lastModifiedComparison %}
                /* Insert new records with incremented version/latest timestamp based on last modified column */
            {%- else %}
                /* New Row Needing To Be Inserted Due To Type-2 Column Changes */
            {%- endif %}
            (
                SELECT {%- if config.selectDistinct %} DISTINCT {%- endif %}
                {%- for col in source.columns if not col.isSurrogateKey %}
                    {%- if col.isSystemVersion %}
                        "DIM"."{{ col.name }}" + 1
                    {%- elif col.isSystemCurrentFlag %}
                        'Y'
                    {%- elif col.name == lastModifiedColName and treatNullAsCurrentTimestamp %}
                        COALESCE({{ get_source_transform(col) }}, CURRENT_TIMESTAMP())
                    {%- else %}
                    {{ get_source_transform(col) }}
                    {%- endif %}
                    AS "{{ col.name }}",
                {%- endfor %}
                    'INSERT_NEW_SCD2_ROWS' AS "DML_OPERATION"
                {{ get_clause(joinclause, 'from') }}

                INNER JOIN {{ ref_no_link(node.location.name, node.name) }} "DIM" ON
                {%- for col in source.columns if col.isBusinessKey %}
                    {%- if not loop.first %}
                        AND
                    {%- endif %}
                    {{ get_source_transform(col) }} = "DIM"."{{ col.name }}"
                {%- endfor %}

                WHERE "DIM"."{{ get_value_by_column_attribute("isSystemCurrentFlag") }}" = 'Y'

                {%- if lastModifiedComparison %}
                    {%- for col in source.columns if col.name == lastModifiedColName %}
                        AND
                        {%- if treatNullAsCurrentTimestamp %}
                        COALESCE({{ get_source_transform(col) }}, CURRENT_TIMESTAMP()) > "DIM"."{{lastModifiedColName}}"
                        {%- else %}
                        {{ get_source_transform(col) }} > "DIM"."{{lastModifiedColName}}"
                        {%- endif %}
                    {%- endfor %}  
                {%- else %}
                    {%- for col in source.columns if (col.isChangeTracking == true) %}
                        {%- if loop.first %}
                            AND (
                        {%- else %}
                            OR
                        {%- endif %}

                        {{- safe_compare(get_source_transform(col), '"DIM"."' ~ col.name ~ '"', col.dataType) -}}

                        {%- if loop.last %} ) {%- endif %}
                    {%- endfor %}
                {%- endif %}
                {{  get_clause(joinclause)  }}
                {%- if config.groupByAll %} GROUP BY ALL {%- endif %}
            )

            UNION ALL

            {%- if lastModifiedComparison %}
                /* Rows Needing To Be Expired - In this case, only two columns are merged (version and end date) */
            {%- else %}
                /*Rows Needing To Be Expired Due To Type-2 Column Changes - In this case, only two columns are merged (version and end date) */
            {%- endif %} 
            (
                SELECT {%- if config.selectDistinct %} DISTINCT {%- endif %}
                {%- for col in source.columns if not col.isSurrogateKey %}
                    {%- if col.isSystemEndDate %}
                        DATEADD(MILLISECONDS, -1, CAST(CURRENT_TIMESTAMP AS TIMESTAMP))
                    {%- elif col.isSystemCurrentFlag %}
                        'N'
                    {%- else %}
                        "DIM"."{{ col.name }}"
                    {%- endif %}
                    AS "{{ col.name }}",
                {%- endfor %}
                'UPDATE_OLD_SCD2_ROWS' AS "DML_OPERATION"
                {{  get_clause(joinclause, 'from')  }}

                INNER JOIN {{ ref_no_link(node.location.name, node.name) }} "DIM" ON
                {%- for col in source.columns if col.isBusinessKey %}
                    {%- if not loop.first %}
                        AND
                    {%- endif %}
                    {{ get_source_transform(col) }} = "DIM"."{{ col.name }}"
                {%- endfor %}

                WHERE "DIM"."{{ get_value_by_column_attribute("isSystemCurrentFlag") }}" = 'Y'

                {%- if lastModifiedComparison %}
                    {%- for col in source.columns if col.name == lastModifiedColName %}
                            AND
                        {%- if treatNullAsCurrentTimestamp %}
                        COALESCE({{ get_source_transform(col) }}, CURRENT_TIMESTAMP()) > "DIM"."{{lastModifiedColName}}"
                        {%- else %}
                        {{ get_source_transform(col) }} > "DIM"."{{lastModifiedColName}}"
                        {%- endif %}
                    {%- endfor %}  
                {%- else %}
                    {%- for col in source.columns if (col.isChangeTracking == true) %}
                        {%- if loop.first %}
                            AND (
                        {%- else %}
                            OR
                        {%- endif %}

                        {{- safe_compare(get_source_transform(col), '"DIM"."' ~ col.name ~ '"', col.dataType) -}}

                        {%- if loop.last %}
                            )
                        {%- endif %}
                    {%- endfor %}
                {%- endif %}
                {{  get_clause(joinclause)  }}
                {%- if config.groupByAll %} GROUP BY ALL {%- endif %}
            )

            {%- if not lastModifiedComparison %}
                {# The if-block below avoids unnecessary updates when no type 2 column changes are present #}
                {%- if source.columns 
                        | rejectattr('isSurrogateKey')
                        | rejectattr('isBusinessKey')
                        | rejectattr('isChangeTracking')
                        | rejectattr('isSystemVersion')
                        | rejectattr('isSystemCurrentFlag')
                        | rejectattr('isSystemStartDate')
                        | rejectattr('isSystemEndDate')
                        | rejectattr('isSystemCreateDate')
                        | rejectattr('isSystemUpdateDate') 
                        | list | length > 0 
                %}

                    UNION ALL

                    /* Rows Needing To Be Updated Due To Changes To Non-Type-2 columns
                    This case merges only when there are changes in non-type-2 column updates, but no changes in type-2 columns*/

                    (
                        SELECT {%- if config.selectDistinct %} DISTINCT {%- endif %}
                        {%- for col in source.columns if not col.isSurrogateKey %}
                            {%- if col.isSystemVersion or col.isSystemCreateDate or col.isSystemStartDate or col.isSystemEndDate %}
                                "DIM"."{{ col.name }}"
                            {%- elif col.isSystemCurrentFlag %}
                                'Y'
                            {%- else %}
                                {{ get_source_transform(col) }}
                            {%- endif %}
                            AS "{{ col.name }}",
                        {%- endfor %}
                        'UPDATE_OLD_SCD1_ROWS' AS "DML_OPERATION"
                        {{  get_clause(joinclause, 'from')  }}

                        INNER JOIN {{ ref_no_link(node.location.name, node.name) }} "DIM" ON
                        {%- for col in source.columns if col.isBusinessKey %}
                            {%- if not loop.first %}
                                AND
                            {%- endif %}
                            {{ get_source_transform(col) }} = "DIM"."{{ col.name }}"
                        {%- endfor %}

                        WHERE "DIM"."{{ get_value_by_column_attribute("isSystemCurrentFlag") }}" = 'Y'
                        AND (
                        {%- for col in source.columns if (col.isChangeTracking) %}
                            {%- if not loop.first %}
                                AND
                            {%- endif %}

                            {{- safe_equals(get_source_transform(col), '"DIM"."' ~ col.name ~ '"', col.dataType) -}}

                        {%- endfor %} )

                        {%- for col in source.columns if not (   col.isBusinessKey or
                                                                col.isChangeTracking or
                                                                col.isSurrogateKey or
                                                                col.isSystemVersion or
                                                                col.isSystemCurrentFlag or
                                                                col.isSystemStartDate or
                                                                col.isSystemEndDate or
                                                                col.isSystemUpdateDate or
                                                                col.isSystemCreateDate) %}
                            {%- if loop.first %}
                                AND (
                            {%- endif %}
                            {%- if not loop.first %}
                                OR
                            {%- endif %}

                            {{- safe_compare(get_source_transform(col), '"DIM"."' ~ col.name ~ '"', col.dataType) -}}

                            {%- if loop.last %} ) {%- endif %}
                        {%- endfor %}

                        {{  get_clause(joinclause)  }}
                        {%- if config.groupByAll %} GROUP BY ALL {%- endif %}
                    ) 
                {%- endif %}
            {%- endif %}
        {%- else %}

            {#== SCD Type 1 ==#}
            (
                SELECT {%- if config.selectDistinct %} DISTINCT {%- endif %}
                {%- for col in source.columns if not col.isSurrogateKey %}
                    {%- if col.isSystemVersion %}
                        1
                    {%- elif col.isSystemCurrentFlag %}
                        'Y'
                    {%- elif col.name == lastModifiedColName and treatNullAsCurrentTimestamp %}
                        COALESCE({{ get_source_transform(col) }}, CURRENT_TIMESTAMP()) AS "{{ col.name }}",
                        COALESCE({{ get_source_transform(col) }}, CURRENT_TIMESTAMP()) as COMPARISON_VALUE,
                        MAX ("DIM"."{{lastModifiedColName}}") AS MAX_TARGET_VALUE		    
                    {%- elif col.name == lastModifiedColName and not treatNullAsCurrentTimestamp %}
                        {{ get_source_transform(col) }} AS "{{ col.name }}",
                        {{ get_source_transform(col) }} AS COMPARISON_VALUE,
                        MAX ("DIM"."{{lastModifiedColName}}") AS MAX_TARGET_VALUE
                    {%- else %}
                        {{ get_source_transform(col) }}
                    {%- endif %}
                    {%- if col.name != lastModifiedColName %} AS "{{ col.name }}" {%- endif %}
                    {%- if not loop.last %}, {%- endif %}
                {%- endfor %}
                {{ get_clause(joinclause, 'from')}}

                {%- if lastModifiedComparison %}
                    LEFT JOIN {{ ref_no_link(node.location.name, node.name) }} "DIM" ON
                    {%- for col in source.columns if col.isBusinessKey %}
                        {%- if not loop.first %}
                            AND
                        {%- endif %}
                        {{ get_source_transform(col) }} = "DIM"."{{ col.name }}"
                    {%- endfor %}
                {%- endif %}
                {%- set clause = get_clause(joinclause) %}
                {%- if clause %}
                    {{ ("WHERE " ~ clause.strip()[3:].strip()) if clause.strip().upper().startswith('AND') else clause }}
                {%- endif %}

                {%- if config.groupByAll or lastModifiedComparison %} GROUP BY ALL {%- endif %}
            )
        {%- endif %}

    ) AS "SRC"
    ON

    {%- for col in columns if col.isBusinessKey %}
        {%- if not loop.first %} AND {%- endif %}
        "TGT"."{{ col.name }}" = "SRC"."{{ col.name }}"
    {%- endfor %}

    {%- if type2Dimension %}
        AND "TGT"."{{ get_value_by_column_attribute("isSystemVersion") }}" = "SRC"."{{ get_value_by_column_attribute("isSystemVersion") }}"
    {%- endif %}

    {%- if type2Dimension %}
        WHEN MATCHED THEN UPDATE SET
        {%- for col in columns if not (col.isBusinessKey or col.isSurrogateKey or col.isSystemCreateDate) %}
            "TGT"."{{ col.name }}" = "SRC"."{{ col.name }}"
            {%- if not loop.last %}, {%- endif %}
        {%- endfor %}

    {%- else %}

        WHEN MATCHED 
        {%- if lastModifiedComparison %}
            AND ("SRC".COMPARISON_VALUE > "SRC".MAX_TARGET_VALUE 
            OR "SRC".MAX_TARGET_VALUE IS NULL)
        {%- else %}  
            {%- for col in columns if not ( col.isBusinessKey or
                                            col.isSurrogateKey or
                                            col.isSystemVersion or
                                            col.isSystemCurrentFlag or
                                            col.isSystemStartDate or
                                            col.isSystemEndDate or
                                            col.isSystemUpdateDate or
                                            col.isSystemCreateDate) %}
                {%- if loop.first %}
                    AND (
                {%- else %}
                    OR
                {%- endif %}

                {{- safe_compare('"SRC"."' ~  col.name ~ '"', '"TGT"."' ~ col.name ~ '"', col.dataType) -}}

                {%- if loop.last %} ) {%- endif %}
            {%- endfor %}
        {%- endif %}

        THEN UPDATE SET
        {%- for col in columns if not (  col.isBusinessKey or
                                        col.isSurrogateKey or
                                        col.isSystemVersion or
                                        col.isSystemCurrentFlag or
                                        col.isSystemStartDate or
                                        col.isSystemCreateDate) %}
            "TGT"."{{ col.name }}" = "SRC"."{{ col.name }}"
            {%- if not loop.last %}, {%- endif %}
        {%- endfor %}
    {%- endif %}

    WHEN NOT MATCHED THEN INSERT
    (
        {%- for col in columns if not col.isSurrogateKey %}
            "{{ col.name }}"
            {%- if not loop.last %}, {%- endif %}
        {%- endfor %}
    )
    VALUES
    (
        {%- for col in columns if not col.isSurrogateKey %}
            "SRC"."{{ col.name }}"
            {%- if not loop.last %}, {%- endif %}
        {%- endfor %}
    )

    {#== Post-SQL ==#}
    {%- if config.postSQL is defined and config.postSQL.parameters is defined %}
        {%- for sql in config.postSQL.parameters %}
            {{ stage('Post-SQL ' + loop.index|string) }}
            {{ sql }}
        {%- endfor %}
    {%- endif %}

{%- else %}
	{{ stage('Load Skipped for View') }}
	-- The node {{node.name}} is materialized as View. Therefore, a Load operation is not supported.
	SELECT 1 AS INFO_MESSAGE WHERE FALSE
{%- endif %}

{# == To run data quality tests after data insertion == #}
{{ run_tests('After') }}

